text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "confirmed_decision": "스모크 테스트가 통과할 경우 금요일 15:00 KST를 공개 릴리스 목표 시점으로 한다.",
        "basis": "수요일 제안에 대해 스모크 테스트 선행 조건이 제기되었고, 최종 결정이 금요일 15:00 KST로 정리되었다."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "confirmed_decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 점검하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "basis": "smoke-theme-pack.mjs에서 mismatch를 무시하자는 제안은 거부되었다."
      }
    ],
    "non_decisions": {
      "rejected_proposals": [
        {
          "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경",
          "result": "거부됨"
        }
      ],
      "internal_stretch_goals": [
        {
          "goal": "수요일 릴리스",
          "status": "내부 스트레치 목표",
          "note": "공개 릴리스 확정 일정이 아니며, 최종 목표 시점은 금요일 15:00 KST이다."
        }
      ],
      "not_finalized": [
        {
          "item": "README 설치 절차 검토",
          "note": "목요일까지 가능하면 검토하자는 의견은 있었지만 담당자 배정은 없었다."
        }
      ]
    },
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래되었으면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 점검한다.",
      "due": null,
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일(가능하면)",
      "status": "미배정",
      "source_certainty": "suggested_without_owner"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 결과가 금요일 10:00 KST까지 공유되었는지 확인",
      "스모크 통과 여부에 따라 공개 릴리스 목표 시점이 금요일 15:00 KST로 유지되는지 확인",
      "Doyun의 실패 트리아지 노트가 금요일 12:00 KST까지 action_items.md에 작성되었는지 확인",
      "Hara의 tarball 경로 점검이 스모크 결과 공유 이후 수행되었는지 확인",
      "README 설치 절차 검토 담당자 지정 여부와 실제 검토 진행 여부 확인",
      "최종 릴리스 승인 권한자와 릴리스 노트의 수요일 스트레치 목표 언급 여부를 후속 결정 항목으로 유지"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "배정되지 않은 담당자",
      "명시되지 않은 추가 마감시한"
    ]
  },
  "non_invention_rules": [
    "인라인 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "명시적으로 확정되지 않은 담당자나 승인권자를 추정하지 않는다.",
    "수요일 일정은 내부 스트레치 목표로만 기록하고 확정 공개 일정으로 승격하지 않는다.",
    "Hara의 작업에는 정확한 마감시한이 없으므로 임의의 due를 넣지 않는다.",
    "README 검토는 제안 수준이며 담당자 미배정 상태로 유지한다.",
    "거부된 제안은 결정 사항으로 재서술하지 않는다."
  ]
}
